import json
import boto3
import botocore
import hashlib
import os


def get_bucket_policy(s3_client, bucket_name):
    try:
        bucket_policy = s3_client.get_bucket_policy(Bucket=bucket_name)
        bucket_policy = json.loads(bucket_policy["Policy"])
        return bucket_policy
    except botocore.exceptions.ClientError as error:
        if error.response["Error"]["Code"] == "NoSuchBucket":
            error_message = f"BUCKET POLICY MODIFICATION FAILED. S3 BUCKET {bucket_name} DOES NOT EXIST."
            raise Exception(error_message)
        elif error.response["Error"]["Code"] == "NoSuchBucketPolicy":
            return None
        elif error.response["Error"]["Code"] == "AccessDenied":
            error_message = f"BUCKET POLICY MODIFICATION FAILED. ACCESS DENIED TO S3 BUCKET {bucket_name}."
            raise Exception(error_message)
        else:
            raise error

def build_ssl_deny_statement(bucket_name, partition, policy_sid):
    return {
        "Sid": policy_sid,
        "Action": "s3:*",
        "Effect": "Deny",
        "Resource": [f"arn:{partition}:s3:::{bucket_name}", f"arn:{partition}:s3:::{bucket_name}/*"],
        "Condition": {"Bool": {"aws:SecureTransport": "false"}},
        "Principal": "*"
    }

def statement_already_exists(bucket_policy, expected_statement):
    if not bucket_policy:
        return False
    for statement in bucket_policy.get("Statement", []):
        if statement.get("Sid") == expected_statement["Sid"]:
            if (statement.get("Action") == expected_statement["Action"] and
                    statement.get("Effect") == expected_statement["Effect"] and
                    statement.get("Principal") == expected_statement["Principal"] and
                    statement.get("Condition") == expected_statement["Condition"] and
                    sorted(statement.get("Resource", [])) == sorted(expected_statement["Resource"])):
                return True
            else:
                raise Exception(
                    f"BUCKET POLICY MODIFICATION FAILED. Statement with SID '{expected_statement['Sid']}' "
                    f"already exists but does not match the expected content. Manual intervention required."
                )
    return False

def generate_policy_statement_id(bucket_name):
    suffix = hashlib.md5(bucket_name.encode(), usedforsecurity=False).hexdigest()[:6]
    return f"AWSConfigRemediation-AllowSSLRequestsOnly_{suffix}"

def update_bucket_policy(bucket_policy, statement):
    if bucket_policy:
        bucket_policy["Statement"].append(statement)
    else:
        bucket_policy = {"Version":"2012-10-17","Statement":[statement]}
    return bucket_policy

def put_bucket_policy(s3_client, bucket_name, bucket_policy):
    bucket_policy = json.dumps(bucket_policy)
    response = s3_client.put_bucket_policy(Bucket=bucket_name, Policy=bucket_policy)
    return response

def verify_bucket_policy_updated(updated_bucket_policy, policy_sid):
    for statement in updated_bucket_policy["Statement"]:
        if statement.get("Sid") == policy_sid:
          if statement.get("Condition").get("Bool").get("aws:SecureTransport") == "false":
            return True
    return False

def get_partition(region):
    partitions = {
        "cn-" : "aws-cn",
        "us-iso-" : "aws-iso",
        "us-isob-" : "aws-iso-b",
        "us-gov-" : "aws-us-gov"
    }
    for key in partitions:
        if key in region:
            partition = partitions[key]
            return partition
    partition = "aws"
    return partition

def handler(event, context):
    s3_client = boto3.client("s3")
    bucket_name = event["BucketName"]
    region = os.environ['AWS_REGION']
    partition = get_partition(region)

    bucket_policy = get_bucket_policy(s3_client, bucket_name)
    policy_sid = generate_policy_statement_id(bucket_name)
    expected_statement = build_ssl_deny_statement(bucket_name, partition, policy_sid)

    if statement_already_exists(bucket_policy, expected_statement):
        return {
            "output": "S3 Bucket already has the expected SSL deny statement. No changes needed.",
            "http_response": {}
        }

    restricted_bucket_policy = update_bucket_policy(bucket_policy, expected_statement)
    response = put_bucket_policy(s3_client, bucket_name, restricted_bucket_policy)
    updated_bucket_policy = get_bucket_policy(s3_client, bucket_name)
    if not verify_bucket_policy_updated(updated_bucket_policy, policy_sid):
        error_message = f"VERIFICATION FAILED. S3 {bucket_name} BUCKET POLICY NOT UPDATED."
        raise Exception(error_message)
    return {
        "output": "Verification of S3 Bucket Policy is successful.",
        "http_response": response
    }
